  1→import supabase from "./supabase.js";
  2→import GenerateEmbeddings from "../utils/GenerateEmbeddings.js";
  3→
  4→const POST_TYPE_CANVAS = 'canvas';
  5→const ALLOWED_STAMP_TYPES = new Set(['heart', 'star', 'question', 'fire']);
  6→const ALLOWED_MARGIN_ITEM_TYPES = new Set(['doodle']);
  7→const STAMP_SELECT = 'id, journal_id, user_id, snippet_id, word_key, stamp_type, x, y, created_at, users!user_id(id, name, image_url)';
  8→const MARGIN_SELECT = 'id, journal_id, user_id, item_type, payload, created_at, updated_at, users!user_id(id, name, image_url)';
  9→const MAX_DOODLE_POINTS = 2400;
 10→const MAX_STICKY_TEXT_LENGTH = 280;
 11→
 12→const normalizeStampPayload = (stamp) => ({
 13→    id: stamp?.id,
 14→    journal_id: stamp?.journal_id,
 15→    user_id: stamp?.user_id,
 16→    snippet_id: stamp?.snippet_id,
 17→    word_key: stamp?.word_key,
 18→    stamp_type: stamp?.stamp_type,
 19→    x: stamp?.x,
 20→    y: stamp?.y,
 21→    created_at: stamp?.created_at,
 22→    user_name: stamp?.users?.name || null,
 23→    user_image_url: stamp?.users?.image_url || null
 24→});
 25→
 26→const normalizeMarginPayload = (item) => ({
 27→    id: item?.id,
 28→    journal_id: item?.journal_id,
 29→    user_id: item?.user_id,
 30→    item_type: item?.item_type,
 31→    payload: item?.payload || null,
 32→    created_at: item?.created_at,
 33→    updated_at: item?.updated_at,
 34→    user_name: item?.users?.name || null,
 35→    user_image_url: item?.users?.image_url || null
 36→});
 37→
 38→const isPlainObject = (value) => Boolean(value) && typeof value === 'object' && !Array.isArray(value);
 39→
 40→const parseNumberInRange = (value, fieldName) => {
 41→    const parsed = Number(value);
 42→    if(Number.isNaN(parsed)){
 43→        throw {status: 400, error: `${fieldName} should be a number`};
 44→    }
 45→    if(parsed < 0 || parsed > 1){
 46→        throw {status: 400, error: `${fieldName} should be between 0 and 1`};
 47→    }
 48→    return parsed;
 49→}
 50→
 51→const extractCanvasPlainText = (canvasDoc) => {
 52→    if(!canvasDoc || !Array.isArray(canvasDoc.snippets)){
 53→        return '';
 54→    }
 55→
 56→    return canvasDoc.snippets
 57→        .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text.trim() : ''))
 58→        .filter(Boolean)
 59→        .join(' ');
 60→}
 61→
 62→const validateDoodlePayload = (payload) => {
 63→    if(!isPlainObject(payload)){
 64→        throw {status: 400, error: 'doodle payload should be an object'};
 65→    }
 66→
 67→    const points = Array.isArray(payload.points) ? payload.points.map((point) => Number(point)) : [];
 68→    if(points.length < 4 || points.length % 2 !== 0){
 69→        throw {status: 400, error: 'doodle payload points should contain at least 2 points'};
 70→    }
 71→    if(points.length > MAX_DOODLE_POINTS){
 72→        throw {status: 400, error: `doodle payload points should not exceed ${MAX_DOODLE_POINTS}`};
 73→    }
 74→    if(points.some((point) => Number.isNaN(point) || point < 0 || point > 1)){
 75→        throw {status: 400, error: 'doodle points should be numbers between 0 and 1'};
 76→    }
 77→
 78→    const size = Number(payload.size);
 79→    const normalizedSize = Number.isNaN(size) ? 2.8 : Math.min(Math.max(size, 1), 14);
 80→    const color = typeof payload.color === 'string' && payload.color.trim()
 81→        ? payload.color.trim().slice(0, 32)
 82→        : '#5f92ff';
 83→
 84→    return {
 85→        points: points,
 86→        size: normalizedSize,
 87→        color: color
 88→    };
 89→}
 90→
 91→const validateStickyPayload = (payload) => {
 92→    if(!isPlainObject(payload)){
 93→        throw {status: 400, error: 'sticky payload should be an object'};
 94→    }
 95→
 96→    const text = typeof payload.text === 'string' ? payload.text.trim() : '';
 97→    if(!text){
 98→        throw {status: 400, error: 'sticky text is required'};
 99→    }
100→    if(text.length > MAX_STICKY_TEXT_LENGTH){
101→        throw {status: 400, error: `sticky text should be less than ${MAX_STICKY_TEXT_LENGTH + 1} characters`};
102→    }
103→
104→    const x = parseNumberInRange(payload.x, 'sticky x');
105→    const y = parseNumberInRange(payload.y, 'sticky y');
106→    const color = typeof payload.color === 'string' && payload.color.trim()
107→        ? payload.color.trim().slice(0, 32)
108→        : '#fff4a8';
109→
110→    return {
111→        text: text,
112→        x: x,
113→        y: y,
114→        color: color
115→    };
116→}
