258→export const getCanvasStampsService = async(journalId, viewerId = null) => {
259→    await assertCanvasJournalAccess(journalId, viewerId);
260→
261→    const {data: stamps, error: stampsError} = await supabase
262→    .from('canvas_stamps')
263→    .select(STAMP_SELECT)
264→    .eq('journal_id', journalId)
265→    .order('created_at', {ascending: true});
266→
267→    if(stampsError){
268→        console.error('supabase error while fetching canvas stamps:', stampsError.message);
269→        throw {status: 500, error: 'supabase error while fetching canvas stamps'};
270→    }
271→
272→    return (stamps || []).map(normalizeStampPayload);
273→}
