275→export const deleteCanvasStampService = async(stampId, userId) => {
276→    if(!stampId){
277→        throw {status: 400, error: 'stampId is undefined'};
278→    }
279→    if(!userId){
280→        throw {status: 401, error: 'userId is undefined'};
281→    }
282→
283→    const {data: stamp, error: stampError} = await supabase
284→    .from('canvas_stamps')
285→    .select('id, user_id, journal_id')
286→    .eq('id', stampId)
287→    .maybeSingle();
288→
289→    if(stampError){
290→        console.error('supabase error while fetching stamp:', stampError.message);
291→        throw {status: 500, error: 'supabase error while fetching canvas stamp'};
292→    }
293→
294→    if(!stamp){
295→        throw {status: 404, error: 'canvas stamp not found'};
296→    }
297→
298→    const journal = await assertCanvasJournalAccess(stamp.journal_id, userId);
299→    const isStampOwner = stamp.user_id === userId;
300→    const isJournalOwner = journal.user_id === userId;
301→    if(!isStampOwner && !isJournalOwner){
302→        throw {status: 403, error: 'not authorized to delete this stamp'};
303→    }
304→
305→    const {error: deleteError} = await supabase
306→    .from('canvas_stamps')
307→    .delete()
308→    .eq('id', stampId);
309→
310→    if(deleteError){
311→        console.error('supabase error while deleting canvas stamp:', deleteError.message);
312→        throw {status: 500, error: 'supabase error while deleting canvas stamp'};
313→    }
314→
315→    return {message: 'success'};
316→}
