399→export const addCanvasMarginService = async({journalId, userId, itemType, payload}) => {
400→    if(!userId){
401→        throw {status: 401, error: 'userId is undefined'};
402→    }
403→
404→    await assertCanvasJournalAccess(journalId, userId);
405→
406→    const normalizedType = typeof itemType === 'string' ? itemType.trim().toLowerCase() : '';
407→    if(!ALLOWED_MARGIN_ITEM_TYPES.has(normalizedType)){
408→        throw {status: 400, error: 'invalid item_type'};
409→    }
410→
411→    const normalizedPayload = normalizedType === 'doodle'
412→        ? validateDoodlePayload(payload)
413→        : validateStickyPayload(payload);
