 246→router.get('/getNotifications', requireAuth, async(req, res) =>{
 247→    const {before, limit} = req.query;
 248→    const userId = req.userId;
 249→
 250→    // Fetch a generous amount from both tables, then merge and paginate
 251→    const fetchLimit = parseInt(limit) + 1;
 252→
 253→    let journalQuery = supabase
 254→    .from('notifications')
 255→    .select(
 256→        `*,
 257→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 258→        users!sender_id(name, user_email, image_url, id, badge)
 259→        `
 260→    )
 261→    .eq('receiver_id', userId)
 262→    .order('created_at', {ascending: false})
 263→    .order('id', {ascending: false})
 264→    .limit(fetchLimit)
 265→
 266→    let opinionQuery = supabase
 267→    .from('notification_opinions')
 268→    .select(
 269→        `*,
 270→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 271→        users!sender_id(name, user_email, image_url, id, badge)
 272→        `
 273→    )
 274→    .eq('receiver_id', userId)
 275→    .order('created_at', {ascending: false})
 276→    .order('id', {ascending: false})
 277→    .limit(fetchLimit)
 278→
 279→    if(before){
 280→        journalQuery = journalQuery.lt('created_at', before);
 281→        opinionQuery = opinionQuery.lt('created_at', before);
 282→    }
 283→
 284→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 285→
 286→    if(journalResult.error){
 287→        console.error('error while fetching data from notification table:', journalResult.error);
 288→        return res.status(500).json({error: 'error fetching data from notification table'});
 289→    }
 290→    if(opinionResult.error){
 291→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 292→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 293→    }
 294→
 295→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 296→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 297→
 298→    // Merge and sort by created_at descending
 299→    const merged = [...journalNotifs, ...opinionNotifs]
 300→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 301→
 302→    // Likes/bookmarks lookup only for journal notifications
 303→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 304→
 305→    let hasLikedResult = [];
 306→    let hasBookMarkedResult = [];
 307→    if(journalIds.length > 0){
 308→        const [hasLiked, hasBookMarked] = await Promise.all([
 309→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 310→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 311→        ]);
 312→
 313→        if(hasLiked.error || hasBookMarked.error){
 314→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 315→        }
 316→        hasLikedResult = hasLiked.data || [];
 317→        hasBookMarkedResult = hasBookMarked.data || [];
 318→    }
 319→
 320→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 321→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 322→
 323→    const formatted = merged.map((notif) => ({
 324→        ...notif,
 325→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 326→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 327→    }))
 328→
 329→    const hasMore = formatted.length > parseInt(limit);
 330→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 331→
 332→    return res.status(200).json(
 333→        {
 334→            hasMore: hasMore,
 335→            data: slicedData,
 336→        }
 337→    )
 338→
 339→})
