 59→const getSnippetMetrics = (snippet, stageWidth) => {
 60→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
 61→    const baseFontSize = snippet.fontStyle === "bold" ? 34 : snippet.fontStyle === "handwritten" ? 32 : 30;
 62→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
 63→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
 64→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
 65→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
 66→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
 67→
 68→    return {width: estimatedWidth, height, fontSize};
 69→};
