 71→const useLoadedImage = (src) => {
 72→    const [image, setImage] = useState(null);
 73→
 74→    useEffect(() => {
 75→        if(!src){
 76→            setImage(null);
 77→            return;
 78→        }
 79→
 80→        const img = new window.Image();
 81→        img.crossOrigin = "anonymous";
 82→        img.onload = () => setImage(img);
 83→        img.onerror = () => setImage(null);
 84→        img.src = src;
 85→
 86→        return () => {
 87→            img.onload = null;
 88→            img.onerror = null;
 89→        };
 90→    }, [src]);
 91→
 92→    return image;
 93→};
