 890→            if(openAuthModal){
 891→                openAuthModal();
 892→            }
 893→            return;
 894→        }
 895→
 896→        if(itemType !== "doodle"){
 897→            return;
 898→        }
 899→
 900→        addMarginMutation.mutate({
 901→            journalId: journalId,
 902→            itemType: itemType,
