 946→        addStampAt({
 947→            stampType: activeStampType,
 948→            x: pointer.x / stageWidth,
 949→            y: pointer.y / stageHeight
 950→        });
 951→    };
 952→
 953→    const getNormalizedPointer = (stage) => {
 954→        const pointer = stage?.getPointerPosition();
 955→        if(!pointer){
 956→            return null;
 957→        }
 958→
 959→        return {
 960→            x: clamp(pointer.x / stageWidth, 0, 1),
