1019→        const nextPoints = [...currentDoodlePointsRef.current, pointer.x, pointer.y];
1020→        currentDoodlePointsRef.current = nextPoints;
1021→        setCurrentDoodlePoints(nextPoints);
1022→        queueDoodleBroadcast({
1023→            journalId: String(journalId),
1024→            clientId: viewerClientIdRef.current,
1025→            userId: currentUserProfile?.id || null,
1026→            points: nextPoints,
1027→            color: doodleColor,
1028→            size: doodleSize,
1029→            updatedAt: Date.now()
