1041→                itemType: "doodle",
1042→                payload: {
1043→                    points: finishedPoints,
1044→                    color: doodleColor,
1045→                    size: doodleSize
1046→                }
1047→            });
1048→        }
1049→
1050→        if(finishedPoints.length >= 2){
1051→            broadcastDoodleEnd(finishedPoints);
1052→        }
1053→
1054→        setIsDrawing(false);
1055→        setCurrentDoodlePoints([]);
1056→        currentDoodlePointsRef.current = [];
1057→    };
1058→
1059→    const handleStageClick = (evt) => {
