1126→        }
1127→
1128→        const stageRect = stageContainer.getBoundingClientRect();
1129→        const localX = event.clientX - stageRect.left;
1130→        const localY = event.clientY - stageRect.top;
1131→
1132→        const normalizedX = localX / stageRect.width;
1133→        const normalizedY = localY / stageRect.height;
1134→        addStampAt({
1135→            stampType: droppedStampType,
1136→            x: normalizedX,
1137→            y: normalizedY
1138→        });
