  1→const DEFAULT_CANVAS_DOC = {
  2→    version: 1,
  3→    meta: {
  4→        aspectRatio: '1:1',
  5→        gridEnabled: true,
  6→        theme: 'light'
  7→    },
  8→    snippets: [],
  9→    images: [],
 10→    doodles: []
 11→};
 12→
 13→const isPlainObject = (value) => value && typeof value === 'object' && !Array.isArray(value);
 14→
 15→const normalizeSnippet = (snippet, index) => {
 16→    if(!isPlainObject(snippet)){
 17→        return null;
 18→    }
 19→
 20→    const text = typeof snippet.text === 'string' ? snippet.text : '';
 21→    const parsedX = Number(snippet.x);
 22→    const parsedY = Number(snippet.y);
 23→    const parsedRotation = Number(snippet.rotation);
 24→    const parsedZIndex = Number(snippet.zIndex);
 25→    const parsedScaleX = Number(snippet.scaleX);
 26→    const parsedSizeScale = Number(snippet.sizeScale);
 27→
 28→    return {
 29→        id: typeof snippet.id === 'string' && snippet.id ? snippet.id : `snippet-${index + 1}`,
 30→        text: text,
 31→        x: Number.isFinite(parsedX) ? Math.min(Math.max(parsedX, 0), 1) : 0.5,
 32→        y: Number.isFinite(parsedY) ? Math.min(Math.max(parsedY, 0), 1) : 0.5,
 33→        rotation: Number.isFinite(parsedRotation) ? parsedRotation : 0,
 34→        zIndex: Number.isFinite(parsedZIndex) ? parsedZIndex : index,
 35→        fontStyle: typeof snippet.fontStyle === 'string' ? snippet.fontStyle : 'serif',
 36→        scaleX: Number.isFinite(parsedScaleX) && (parsedScaleX === 1 || parsedScaleX === -1) ? parsedScaleX : 1,
 37→        sizeScale: Number.isFinite(parsedSizeScale) ? Math.min(Math.max(parsedSizeScale, 0.6), 2.5) : 1
 38→    };
 39→};
 40→
 41→const normalizeImage = (image, index) => {
 42→    if(!isPlainObject(image)){
 43→        return null;
 44→    }
 45→
 46→    const parsedX = Number(image.x);
 47→    const parsedY = Number(image.y);
 48→    const parsedWidth = Number(image.width);
 49→    const parsedHeight = Number(image.height);
 50→    const parsedRotation = Number(image.rotation);
 51→    const parsedZIndex = Number(image.zIndex);
 52→    const parsedScaleX = Number(image.scaleX);
 53→
 54→    return {
 55→        id: typeof image.id === 'string' && image.id ? image.id : `image-${index + 1}`,
 56→        src: typeof image.src === 'string' ? image.src : '',
 57→        x: Number.isFinite(parsedX) ? Math.min(Math.max(parsedX, 0), 1) : 0.5,
 58→        y: Number.isFinite(parsedY) ? Math.min(Math.max(parsedY, 0), 1) : 0.5,
 59→        width: Number.isFinite(parsedWidth) ? Math.max(0.08, Math.min(parsedWidth, 1)) : 0.28,
 60→        height: Number.isFinite(parsedHeight) ? Math.max(0.08, Math.min(parsedHeight, 1.2)) : 0.22,
 61→        rotation: Number.isFinite(parsedRotation) ? parsedRotation : 0,
 62→        zIndex: Number.isFinite(parsedZIndex) ? parsedZIndex : index,
 63→        scaleX: Number.isFinite(parsedScaleX) && (parsedScaleX === 1 || parsedScaleX === -1) ? parsedScaleX : 1
 64→    };
 65→};
 66→
 67→const normalizeDoodle = (doodle, index) => {
 68→    if(!isPlainObject(doodle)){
 69→        return null;
 70→    }
 71→
 72→    const rawPoints = Array.isArray(doodle.points) ? doodle.points : [];
 73→    const points = rawPoints
 74→        .map((point) => Number(point))
 75→        .filter((point) => Number.isFinite(point))
 76→        .map((point) => Math.min(Math.max(point, 0), 1));
 77→
 78→    if(points.length < 4){
 79→        return null;
 80→    }
 81→
 82→    const normalizedPoints = points.length % 2 === 0 ? points : points.slice(0, -1);
 83→    if(normalizedPoints.length < 4){
 84→        return null;
 85→    }
 86→
 87→    const parsedSize = Number(doodle.size);
 88→    return {
 89→        id: typeof doodle.id === 'string' && doodle.id ? doodle.id : `doodle-${index + 1}`,
 90→        points: normalizedPoints,
 91→        color: typeof doodle.color === 'string' && doodle.color.trim() ? doodle.color.trim().slice(0, 32) : '#5f92ff',
 92→        size: Number.isFinite(parsedSize) ? Math.min(Math.max(parsedSize, 1), 14) : 2.8
 93→    };
 94→};
 95→
 96→export const parseCanvasDoc = (rawCanvasDoc) => {
 97→    if(!rawCanvasDoc){
 98→        return {...DEFAULT_CANVAS_DOC};
 99→    }
100→
101→    try {
102→        const parsed = typeof rawCanvasDoc === 'string' ? JSON.parse(rawCanvasDoc) : rawCanvasDoc;
103→        if(!isPlainObject(parsed)){
104→            return {...DEFAULT_CANVAS_DOC};
105→        }
106→
107→        const snippets = Array.isArray(parsed.snippets)
108→            ? parsed.snippets
109→                .map((snippet, index) => normalizeSnippet(snippet, index))
110→                .filter(Boolean)
111→            : [];
112→        const images = Array.isArray(parsed.images)
113→            ? parsed.images
114→                .map((image, index) => normalizeImage(image, index))
115→                .filter(Boolean)
116→            : [];
117→        const doodles = Array.isArray(parsed.doodles)
118→            ? parsed.doodles
119→                .map((doodle, index) => normalizeDoodle(doodle, index))
120→                .filter(Boolean)
121→            : [];
122→
123→        return {
124→            version: 1,
125→            meta: {
126→                aspectRatio: parsed?.meta?.aspectRatio === '4:5' ? '4:5' : '1:1',
127→                gridEnabled: Boolean(parsed?.meta?.gridEnabled),
128→                theme: parsed?.meta?.theme === 'dark' ? 'dark' : 'light'
129→            },
130→            snippets: snippets,
131→            images: images,
132→            doodles: doodles
133→        };
134→    } catch (error) {
135→        console.error('Error parsing canvas doc:', error);
136→        return {...DEFAULT_CANVAS_DOC};
137→    }
138→};
139→
140→export const getCanvasWholeText = (rawCanvasDoc) => {
141→    const canvasDoc = parseCanvasDoc(rawCanvasDoc);
142→    return canvasDoc.snippets
143→        .map((snippet) => snippet.text.trim())
144→        .filter(Boolean)
145→        .join(' ');
146→};
147→
148→export const getCanvasPreview = (rawCanvasDoc, maxLength = 215) => {
149→    const wholeText = getCanvasWholeText(rawCanvasDoc);
150→    const slicedText = wholeText.length > maxLength ? `${wholeText.substring(0, maxLength)}...` : wholeText;
151→
152→    return {
153→        wholeText: wholeText,
154→        slicedText: slicedText
155→    };
156→};
