473→export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest') => {
474→    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
475→        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
476→    }
477→
478→    const parsedLimit = parseInt(limit);
479→    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
480→    const isNewest = normalizedSort === 'newest';
481→
482→    const fetchLimit = isNewest ? parsedLimit : Math.min(Math.max(parsedLimit * 4, parsedLimit), 220);
483→    const {data: journals, error: journalsError} = await supabase
484→    .from('journals')
485→    .select(`
486→        *,
487→        users(*),
488→        like_count: likes(count),
489→        comment_count: comments(count),
490→        bookmark_count: bookmarks(count),
491→        stamp_count: canvas_stamps(count),
492→        margin_count: canvas_margin_items(count)
493→    `)
494→    .eq('privacy', 'public')
495→    .eq('post_type', 'canvas')
496→    .order('created_at', {ascending: false})
497→    .order('id', {ascending: false})
498→    .limit(fetchLimit);
499→
500→    if(journalsError){
501→        console.error('supabase error while fetching canvas gallery journals:', journalsError.message);
502→        throw {status: 500, error: 'supabase error while fetching canvas gallery journals'};
503→    }
504→
505→    const enrichedJournals = await attachUserInteractionFlags(journals || [], userId);
506→    const normalizedJournals = enrichedJournals.map((journal) => ({
507→        ...journal,
508→        hot_score: scoreJournalHotness(journal)
509→    }));
510→
511→    if(!isNewest){
512→        normalizedJournals.sort((a, b) => {
513→            const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
514→            if(scoreDiff !== 0){
515→                return scoreDiff;
516→            }
517→
518→            const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
519→            if(dateDiff !== 0){
520→                return dateDiff;
521→            }
522→
523→            return (b?.id || 0) - (a?.id || 0);
524→        });
525→    }
526→
527→    return {
528→        data: normalizedJournals.slice(0, parsedLimit),
529→        sort: isNewest ? 'newest' : 'hottest',
530→        totalCandidates: normalizedJournals.length
531→    };
532→}
